SELECT motos1.medio AS medio FROM motos1 WHERE (('Cerrar' = 'Cerrar') AND (motos1.categoria IN ('CAMIONES', 'CAMIONES, BUSES Y PANELES', 'MOTOCICLETAS', 'PICK UPS, VANS Y JEEPS', 'PICK-UPS', 'SUV Y JEEPS', 'VEHICULOS NUEVOS')) AND (CAST(EXTRACT(YEAR FROM motos1.fecha) AS BIGINT) >= 2010) AND (CAST(EXTRACT(YEAR FROM motos1.fecha) AS BIGINT) <= 2015) AND (motos1.categoria = 'MOTOCICLETAS') AND (motos1.marca IN ('MOTOCICLETAS YAMAHA', 'YAMAHA')) AND (CAST(EXTRACT(MONTH FROM motos1.fecha) AS BIGINT) >= 1) AND (CAST(EXTRACT(MONTH FROM motos1.fecha) AS BIGINT) <= 9)) GROUP BY motos1.medio;
